// Build the LLM prompt from user data
const input = $input.first().json;
const body = input.body || input;
const userId = body.user_id || '';
const preferences = body.preferences || [];
const interactions = body.recent_interactions || [];
const overrides = body.overrides || [];

// Format preferences
const prefsText = preferences.map(p => `${p.preference_type}: ${p.preference_value}`).join('\n');

// Format interactions
const likedTopics = interactions.filter(i => i.interaction_type === 'like').map(i => i.cluster_topic || 'unknown').join(', ');
const dislikedTopics = interactions.filter(i => i.interaction_type === 'dislike').map(i => i.cluster_topic || 'unknown').join(', ');

// Format overrides (excluded items)
const excludeText = overrides.length > 0 ? overrides.join(', ') : 'none';

const prompt = `Based on this user's explicit preferences and behavioral data, generate a structured JSON profile.

Explicit preferences:
${prefsText || 'none set'}

Recent likes: ${likedTopics || 'none'}
Recent dislikes: ${dislikedTopics || 'none'}
Items to EXCLUDE (user manually removed): ${excludeText}

Return JSON only, no preamble:
{
  "inferred_interests": ["topic1", "topic2"],
  "avoided_topics": ["topic3"],
  "preferred_depth": "deep_analysis" | "quick_scan" | "balanced",
  "geographic_focus": ["region1", "region2"],
  "industry_focus": ["industry1"],
  "lens_preferences": ["lens1"]
}`;

return [{ json: { userId, prompt } }];

// Parse Claude response and upsert to ai_user_profiles
const userId = $('Build Prompt').first().json.userId;
const response = $input.first().json;

let profile;
try {
  let text = response.content?.[0]?.text || '{}';
  if (text.startsWith('```')) text = text.split('\n', 2)[1].split('```')[0].trim();
  profile = JSON.parse(text);
} catch (e) {
  profile = {
    inferred_interests: [],
    avoided_topics: [],
    preferred_depth: 'balanced',
    geographic_focus: [],
    industry_focus: [],
    lens_preferences: []
  };
}

return [{ json: { userId, profile } }];
